### Step 2: Player Turns and Move Validation

We'll create a class to handle player turns and move validation.

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = "white"

    def switch_player(self):
        if self.current_player == "white":
            self.current_player = "black"
        else:
            self.current_player = "white"

    def is_valid_move(self, start: Tuple[int, int], end: Tuple[int, int]) -> bool:
        piece = self.board.board[start[0]][start[1]]
        if piece is None or piece.color != self.current_player:
            return False

        dx, dy = end[0] - start[0], end[1] - start[1]
        if abs(dx) != 1 or abs(dy) not in [1, 2]:
            return False

        if abs(dy) == 2:  # Jump
            mid_piece = self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
            if mid_piece is None or mid_piece.color == piece.color:
                return False

        if abs(dy) == 1:  # Normal move
            if self.board.board[end[0]][end[1]] is not None:
                return False

        return True

    def make_move(self, start: Tuple[int, int], end: Tuple[int, int]):
        piece = self.board.board[start[0]][start[1]]
        self.board.board[start[0]][start[1]] = None
        self.board.board[end[0]][end[1]] = piece

        if abs(end[1] - start[1]) == 2:  # Jumped, remove the mid piece
            mid_piece = self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
            self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2] = None

        if end[0] == 0 and piece.color == "white":
            piece.make_king()
        elif end[0] == 7 and piece.color == "black":
            piece.make_king()

        self.switch_player()

    def get_valid_moves(self, start: Tuple[int, int]) -> List[Tuple[int, int]]:
        moves = []
        for dx in [-1, 1]:
            if abs(start[1] + dx) < 8:
                end = (start[0] + dx, start[1] + dx)
                if self.is_valid_move(start, end):
                    moves.append(end)

                if abs(dx) == 2 and self.board.board[(start[0] + dx) // 2][(start[1] + dx) // 2] is not None:
                    second_end = (start[0] + 2 * dx, start[1] + 2 * dx)
                    if self.is_valid_move(start, second_end):
                        moves.append(second_end)

        return moves

    def get_all_moves(self) -> List[Tuple[int, int]]:
        all_moves = []
        for i in range(8):
            for j in range(8):
                piece = self.board.board[i][j]
                if piece is not None and piece.color == self.current_player:
                    all_moves.extend(self.get_valid_moves((i, j)))
        return all_moves
