            return True
        if abs(end_row - start_row) == 2 and abs(end_col - start_col) == 2:
            middle_piece = self.get_piece((start_row + end_row) // 2, (start_col + end_col) // 2)
            return middle_piece and middle_piece.color != piece.color
        return False

    def move(self, start_row, start_col, end_row, end_col):
